changeSet.sql:
CREATE TABLE IF NOT EXISTS agent_profiles ( id INT NOT NULL AUTO_INCREMENT, character_id INT NOT NULL, ownership_type VARCHAR(16) NOT NULL DEFAULT 'SERVER', owner_account_id INT DEFAULT NULL, owner_character_id INT DEFAULT NULL, enabled TINYINT NOT NULL DEFAULT 0, display_name VARCHAR(32) DEFAULT NULL, default_mode VARCHAR(32) NOT NULL DEFAULT 'IDLE', behavior_profile VARCHAR(64) NOT NULL DEFAULT 'default', personality_profile VARCHAR(64) NOT NULL DEFAULT 'default', script_name VARCHAR(128) DEFAULT NULL, llm_enabled TINYINT NOT NULL DEFAULT 0, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, PRIMARY KEY (id), UNIQUE KEY uk_agent_profiles_character (character_id), KEY idx_agent_profiles_owner_account (owner_account_id), KEY idx_agent_profiles_owner_character (owner_character_id), KEY idx_agent_profiles_enabled_mode (enabled, default_mode) );
CREATE TABLE IF NOT EXISTS agent_runtime_sessions ( id BIGINT NOT NULL AUTO_INCREMENT, agent_profile_id INT NOT NULL, character_id INT NOT NULL, world INT NOT NULL DEFAULT 0, channel INT NOT NULL DEFAULT 1, map_id INT NOT NULL DEFAULT 0, state VARCHAR(32) NOT NULL DEFAULT 'OFFLINE', current_goal_id BIGINT DEFAULT NULL, current_task VARCHAR(128) DEFAULT NULL, started_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, last_tick_at TIMESTAMP NULL DEFAULT NULL, ended_at TIMESTAMP NULL DEFAULT NULL, stop_reason VARCHAR(255) DEFAULT NULL, PRIMARY KEY (id), KEY idx_agent_sessions_profile_state (agent_profile_id, state), KEY idx_agent_sessions_character_ended (character_id, ended_at), KEY idx_agent_sessions_location (world, channel, map_id) );
CREATE TABLE IF NOT EXISTS agent_goals ( id BIGINT NOT NULL AUTO_INCREMENT, agent_profile_id INT NOT NULL, goal_type VARCHAR(64) NOT NULL, priority INT NOT NULL DEFAULT 0, status VARCHAR(32) NOT NULL DEFAULT 'PENDING', target_world INT DEFAULT NULL, target_channel INT DEFAULT NULL, target_map INT DEFAULT NULL, target_ref VARCHAR(128) DEFAULT NULL, parameters_json TEXT DEFAULT NULL, progress_json TEXT DEFAULT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, started_at TIMESTAMP NULL DEFAULT NULL, completed_at TIMESTAMP NULL DEFAULT NULL, PRIMARY KEY (id), KEY idx_agent_goals_profile_status_priority (agent_profile_id, status, priority), KEY idx_agent_goals_type_status (goal_type, status) );
CREATE TABLE IF NOT EXISTS agent_scripts ( id INT NOT NULL AUTO_INCREMENT, name VARCHAR(128) NOT NULL, version INT NOT NULL DEFAULT 1, enabled TINYINT NOT NULL DEFAULT 0, script_type VARCHAR(32) NOT NULL DEFAULT 'YAML', body MEDIUMTEXT NOT NULL, created_by VARCHAR(64) DEFAULT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, PRIMARY KEY (id), UNIQUE KEY uk_agent_scripts_name (name), KEY idx_agent_scripts_enabled (enabled) );
CREATE TABLE IF NOT EXISTS agent_memory_events ( id BIGINT NOT NULL AUTO_INCREMENT, agent_profile_id INT NOT NULL, event_type VARCHAR(64) NOT NULL, importance INT NOT NULL DEFAULT 0, related_character_id INT DEFAULT NULL, related_agent_profile_id INT DEFAULT NULL, map_id INT DEFAULT NULL, summary VARCHAR(512) NOT NULL, details_json TEXT DEFAULT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (id), KEY idx_agent_memory_profile_time (agent_profile_id, created_at), KEY idx_agent_memory_type_time (event_type, created_at) );
CREATE TABLE IF NOT EXISTS agent_relationships ( id BIGINT NOT NULL AUTO_INCREMENT, agent_profile_id INT NOT NULL, related_character_id INT NOT NULL, relationship_type VARCHAR(32) NOT NULL DEFAULT 'NEUTRAL', trust_score INT NOT NULL DEFAULT 0, affinity_score INT NOT NULL DEFAULT 0, notes VARCHAR(512) DEFAULT NULL, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, PRIMARY KEY (id), UNIQUE KEY uk_agent_relationships_character (agent_profile_id, related_character_id), KEY idx_agent_relationships_related_character (related_character_id) );
CREATE TABLE IF NOT EXISTS agent_action_logs ( id BIGINT NOT NULL AUTO_INCREMENT, agent_profile_id INT NOT NULL, runtime_session_id BIGINT DEFAULT NULL, action_type VARCHAR(64) NOT NULL, status VARCHAR(32) NOT NULL DEFAULT 'OK', world INT DEFAULT NULL, channel INT DEFAULT NULL, map_id INT DEFAULT NULL, target_type VARCHAR(32) DEFAULT NULL, target_id BIGINT DEFAULT NULL, message VARCHAR(512) DEFAULT NULL, details_json TEXT DEFAULT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (id), KEY idx_agent_actions_profile_time (agent_profile_id, created_at), KEY idx_agent_actions_type_time (action_type, created_at), KEY idx_agent_actions_session (runtime_session_id) );
CREATE TABLE IF NOT EXISTS agent_chat_logs ( id BIGINT NOT NULL AUTO_INCREMENT, agent_profile_id INT NOT NULL, runtime_session_id BIGINT DEFAULT NULL, channel_type VARCHAR(32) NOT NULL, direction VARCHAR(16) NOT NULL, sender_character_id INT DEFAULT NULL, recipient_character_id INT DEFAULT NULL, message VARCHAR(512) NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (id), KEY idx_agent_chat_profile_time (agent_profile_id, created_at), KEY idx_agent_chat_channel_time (channel_type, created_at) );
CREATE TABLE IF NOT EXISTS agent_economy_ledger ( id BIGINT NOT NULL AUTO_INCREMENT, agent_profile_id INT NOT NULL, runtime_session_id BIGINT DEFAULT NULL, entry_type VARCHAR(64) NOT NULL, item_id INT DEFAULT NULL, quantity INT NOT NULL DEFAULT 0, meso_delta BIGINT NOT NULL DEFAULT 0, source_type VARCHAR(32) DEFAULT NULL, source_id BIGINT DEFAULT NULL, counterparty_character_id INT DEFAULT NULL, world INT DEFAULT NULL, channel INT DEFAULT NULL, map_id INT DEFAULT NULL, details_json TEXT DEFAULT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (id), KEY idx_agent_economy_profile_time (agent_profile_id, created_at), KEY idx_agent_economy_item_time (item_id, created_at), KEY idx_agent_economy_entry_time (entry_type, created_at), KEY idx_agent_economy_counterparty_time (counterparty_character_id, created_at) );
CREATE TABLE IF NOT EXISTS agent_policies ( id INT NOT NULL AUTO_INCREMENT, agent_profile_id INT NOT NULL DEFAULT 0, scope VARCHAR(32) NOT NULL DEFAULT 'GLOBAL', policy_key VARCHAR(128) NOT NULL, policy_value VARCHAR(512) NOT NULL, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, PRIMARY KEY (id), UNIQUE KEY uk_agent_policies_key (agent_profile_id, scope, policy_key), KEY idx_agent_policies_scope_key (scope, policy_key) );
